VALUES
  ('generalpolice-94737317-moex-00372', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '關於監察院之組織，下列敘述何者錯誤？', '["設院長、副院長各1人，由總統提名時指定，經立法院同意任命之", "設監察委員29人，任期6年", "設國家人權委員會，由院長兼任主任委員", "設審計長，由監察院院長遴派之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00373', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '下列何者並非憲法第80條之法官？', '["大法官", "懲戒法院法官", "家事法院法官", "檢察官"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00374', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '有關司法院大法官解釋效力，下列敘述何者錯誤？', '["確定終局裁判所適用之法律或命令，經依人民聲請解釋認為與憲法意旨不符，凡曾因同一法令受不利確 定終局裁判者，均得以該解釋為再審或非常上訴之理由", "人民聲請解釋憲法，宣告確定終局裁判所適用之法令定期失效者，聲請人就原因案件應得據以請求再審 或其他救濟", "依司法院釋字第 741 號解釋，凡大法官宣告法令違憲並定期失效者，各該解釋之聲請人均得就其原因 案件據以請求再審或其他救濟", "解釋之聲請人得在其確定終局裁判所適用之法令遭宣告失效後，得就其原因案件據以請求再審或其他 救濟，係為保障聲請人之權益，並肯定其對維護憲法之貢獻"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00375', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '下列何者不是憲法訴訟法規定的聲請程序類型？', '["機關爭議", "法令違憲之疑義", "行使職權，適用憲法之疑義", "裁判違憲之疑義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00376', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '依據司法院釋字第 498 號解釋，地方自治團體之行政首長與民意代表均應由自治區域內之人民依法選舉 產生，係基於住民自治之理念與下列何者之功能？', '["垂直分權", "國家主權", "社會正義", "階級和諧"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00377', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '以下有關成文法源之敘述，何者錯誤？', '["憲法規範人民基本權利及國家組織，是所有成文法源中，效力位階最高者", "作為成文法源的法律，指的是狹義的法律，依中央法規標準法之規定，其名稱包含法、律、條例、通則", "依地方制度法規定，地方自治法規之種類包含經地方議會三讀通過的自治條例，以及地方政府訂定發布 的行政規則", "條約必須經過行政院會議決議，並送交立法院審議通過及總統公布後，才會產生拘束力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00378', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '以下有關法律繼受及固有法的敘述，何者錯誤？', '["固有法係根據一國固有的社會狀態、風土民情及生活習慣而制定之法律，繼受法則係仿造外國法之內容 而制定出來之法律", "我國現行的民法典，多係繼受自英、法等國的民法典規定而來", "法律的繼受依其方法，可以分為藉由司法裁判而為之習慣法的繼受，以及藉由立法機關而為的立法繼受", "日耳曼各國在13、14世紀對於羅馬法的繼受，即屬習慣法的繼受"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00379', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '大法官解釋案件時參考制憲、修憲及立法資料，此種解釋方式為何？', '["文義解釋", "當然解釋", "歷史解釋", "體系解釋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00380', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '最高法院曾有判決認定，關於想像競合犯，部分犯罪事實是否構成自首，須參照法條編排因素來解釋。此 係何種法律解釋方法？', '["文義解釋", "目的解釋", "歷史解釋", "體系解釋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00381', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '法規就違反構成要件者，課處600元至1,800元之罰鍰制裁。下列何項情形，構成「裁量逾越」之瑕疵？', '["行政機關課處違法行為人3,000元之罰鍰", "行政機關就任何違法行為人一律課處1,800元之罰鍰", "行政機關就初犯之行為人課處1,800元之罰鍰", "行政機關就違反同一要件之不同行為人，課處不同額度之罰鍰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
